import React, { useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import styles from '../styles/inlineStyles';

const Navigation = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav style={styles.nav}>
      <div style={styles.navInner}>
        <h2 style={{ margin: 0, cursor: 'pointer', fontSize: '20px', color: 'white' }} onClick={() => navigate('/dashboard')}>
          Learn bridge
        </h2>

      <div style={{ display: 'flex', gap: '20px', alignItems: 'center', flexWrap: 'wrap' }}>
        {user && (
          <>
            <a onClick={() => navigate('/dashboard')} style={styles.navLink}>
              Home
            </a>

            {user.role === 'student' && (
              <>
                <a onClick={() => navigate('/study-planner')} style={styles.navLink}>
                  Planner
                </a>
                <a onClick={() => navigate('/materials')} style={styles.navLink}>
                  Materials
                </a>
                <a onClick={() => navigate('/questions')} style={styles.navLink}>
                  Q&A
                </a>
                <a onClick={() => navigate('/mcq')} style={styles.navLink}>
                  MCQ
                </a>
                <a onClick={() => navigate('/appointments')} style={styles.navLink}>
                  Sessions
                </a>
                <a onClick={() => navigate('/progress')} style={styles.navLink}>
                  Progress
                </a>
              </>
            )}

            {user.role === 'tutor' && (
              <>
                <a onClick={() => navigate('/subjects')} style={styles.navLink}>
                  Subjects
                </a>
                <a onClick={() => navigate('/materials')} style={styles.navLink}>
                  Materials
                </a>
                <a onClick={() => navigate('/questions')} style={styles.navLink}>
                  Q&A
                </a>
                <a onClick={() => navigate('/sessions')} style={styles.navLink}>
                  Sessions
                </a>
              </>
            )}

            <a onClick={() => navigate('/profile')} style={styles.navLink}>
              {user.name}
            </a>
            <button onClick={handleLogout} style={{ ...styles.buttonDanger, padding: '8px 16px' }}>
              Logout
            </button>
          </>
        )}
      </div>
      </div>
    </nav>
  );
};

export default Navigation;
